import React, { useState } from 'react';
import { Search, Filter, Clock, BookOpen, Users, Star, Play, Gift, Plus } from 'lucide-react';
import { Link } from 'react-router-dom';

interface Scenario {
  id: number;
  title: string;
  description: string;
  category: string;
  difficulty: 'Beginner' | 'Intermediate' | 'Advanced' | 'Expert';
  duration: string;
  rating: number;
  participants: number;
  points: number;
  isNew?: boolean;
  isFree?: boolean;
}

const ScenarioBrowser: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [selectedDifficulty, setSelectedDifficulty] = useState('All');

  const categories = ['All', 'Criminal Law', 'Civil Law', 'Corporate Law', 'Family Law', 'Constitutional Law'];
  const difficulties = ['All', 'Beginner', 'Intermediate', 'Advanced', 'Expert'];

  const scenarios: Scenario[] = [
    {
      id: 1,
      title: "Cross-Examination of a Hostile Witness",
      description: "Practice techniques for handling uncooperative witnesses in a criminal trial setting.",
      category: "Criminal Law",
      difficulty: "Intermediate",
      duration: "45 min",
      rating: 4.8,
      participants: 1240,
      points: 0,
      isNew: true,
      isFree: true
    },
    {
      id: 2,
      title: "Drafting a Commercial Contract",
      description: "Create a comprehensive contract for a software licensing agreement with multiple clauses.",
      category: "Corporate Law",
      difficulty: "Advanced",
      duration: "90 min",
      rating: 4.6,
      participants: 890,
      points: 1500
    },
    {
      id: 3,
      title: "Family Mediation Session",
      description: "Facilitate a divorce mediation between parties with conflicting interests and emotional tensions.",
      category: "Family Law",
      difficulty: "Intermediate",
      duration: "60 min",
      rating: 4.7,
      participants: 750,
      points: 1200
    },
    {
      id: 4,
      title: "Constitutional Writ Petition",
      description: "Prepare and argue a writ petition challenging a government policy on constitutional grounds.",
      category: "Constitutional Law",
      difficulty: "Expert",
      duration: "120 min",
      rating: 4.9,
      participants: 520,
      points: 2500
    },
    {
      id: 5,
      title: "Client Consultation for Personal Injury",
      description: "Conduct an initial consultation with a client who has suffered workplace injuries.",
      category: "Civil Law",
      difficulty: "Beginner",
      duration: "30 min",
      rating: 4.5,
      participants: 2100,
      points: 0,
      isFree: true
    },
    {
      id: 6,
      title: "Bail Application Hearing",
      description: "Represent a defendant seeking anticipatory bail in a complex criminal matter.",
      category: "Criminal Law",
      difficulty: "Intermediate",
      duration: "45 min",
      rating: 4.4,
      participants: 1650,
      points: 1000
    }
  ];

  const filteredScenarios = scenarios.filter(scenario => {
    const matchesSearch = scenario.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          scenario.description.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === 'All' || scenario.category === selectedCategory;
    const matchesDifficulty = selectedDifficulty === 'All' || scenario.difficulty === selectedDifficulty;
    
    return matchesSearch && matchesCategory && matchesDifficulty;
  });

  const getDifficultyColor = (difficulty: string) => {
    switch (difficulty) {
      case 'Beginner': return 'bg-green-100 text-green-800';
      case 'Intermediate': return 'bg-blue-100 text-blue-800';
      case 'Advanced': return 'bg-yellow-100 text-yellow-800';
      case 'Expert': return 'bg-red-100 text-red-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  return (
    <div className="container mx-auto px-4 py-12">
      <div className="text-center max-w-3xl mx-auto mb-12">
        <h1 className="text-3xl md:text-4xl font-bold text-gray-900 mb-6">
          Legal Scenario Library
        </h1>
        <p className="text-xl text-gray-600">
          Practice with hundreds of realistic legal scenarios designed by experienced practitioners
        </p>
        <div className="mt-6">
          <Link to="/create-scenario">
            <button className="inline-flex items-center bg-gradient-to-r from-indigo-600 to-purple-600 text-white px-6 py-3 rounded-lg hover:from-indigo-700 hover:to-purple-700 transition duration-300 font-medium">
              <Plus className="w-5 h-5 mr-2" />
              Create Custom Scenario
            </button>
          </Link>
          <p className="mt-3 text-sm text-gray-500">
            Premium feature: 1000 points for 5 custom scenarios per month
          </p>
        </div>
      </div>

      {/* Search and Filters */}
      <div className="bg-white rounded-xl shadow-sm p-6 mb-8">
        <div className="flex flex-col md:flex-row gap-4 mb-6">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-5 h-5" />
            <input
              type="text"
              placeholder="Search scenarios..."
              className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button className="bg-indigo-600 text-white px-6 py-3 rounded-lg hover:bg-indigo-700 transition duration-300 font-medium flex items-center">
            <Filter className="w-5 h-5 mr-2" />
            Advanced Filters
          </button>
        </div>

        <div className="flex flex-wrap gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Category</label>
            <select 
              className="border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
              value={selectedCategory}
              onChange={(e) => setSelectedCategory(e.target.value)}
            >
              {categories.map(category => (
                <option key={category} value={category}>{category}</option>
              ))}
            </select>
          </div>
          
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Difficulty</label>
            <select 
              className="border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
              value={selectedDifficulty}
              onChange={(e) => setSelectedDifficulty(e.target.value)}
            >
              {difficulties.map(difficulty => (
                <option key={difficulty} value={difficulty}>{difficulty}</option>
              ))}
            </select>
          </div>
          
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Access Type</label>
            <select className="border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent">
              <option>All Types</option>
              <option>Free Only</option>
              <option>Premium Only</option>
            </select>
          </div>
        </div>
      </div>

      {/* Scenario Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {filteredScenarios.map(scenario => (
          <div 
            key={scenario.id} 
            className="bg-white rounded-xl shadow-sm hover:shadow-md transition duration-300 overflow-hidden border border-gray-100"
          >
            <div className="p-6">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <span className={`inline-block px-3 py-1 rounded-full text-xs font-medium ${getDifficultyColor(scenario.difficulty)}`}>
                    {scenario.difficulty}
                  </span>
                  {scenario.isNew && (
                    <span className="ml-2 inline-block px-3 py-1 rounded-full text-xs font-medium bg-purple-100 text-purple-800">
                      New
                    </span>
                  )}
                  {scenario.isFree && (
                    <span className="ml-2 inline-block px-3 py-1 rounded-full text-xs font-medium bg-green-100 text-green-800">
                      Free
                    </span>
                  )}
                </div>
                <div className="flex items-center text-yellow-500">
                  <Star className="w-4 h-4 fill-current" />
                  <span className="ml-1 text-gray-700 text-sm">{scenario.rating}</span>
                </div>
              </div>
              
              <h3 className="text-xl font-bold text-gray-900 mb-2">{scenario.title}</h3>
              <p className="text-gray-600 mb-4">{scenario.description}</p>
              
              <div className="flex flex-wrap gap-2 mb-6">
                <div className="flex items-center text-gray-500 text-sm">
                  <BookOpen className="w-4 h-4 mr-1" />
                  {scenario.category}
                </div>
                <div className="flex items-center text-gray-500 text-sm">
                  <Clock className="w-4 h-4 mr-1" />
                  {scenario.duration}
                </div>
                <div className="flex items-center text-gray-500 text-sm">
                  <Users className="w-4 h-4 mr-1" />
                  {scenario.participants.toLocaleString()}
                </div>
              </div>
              
              <div className="flex justify-between items-center mb-4">
                {scenario.isFree ? (
                  <div className="text-lg font-bold text-green-600">FREE</div>
                ) : (
                  <div className="flex items-center text-indigo-600">
                    <Gift className="w-4 h-4 mr-1" />
                    <span className="font-bold">{scenario.points} points</span>
                  </div>
                )}
              </div>
              
              <button className="w-full bg-indigo-600 text-white py-3 rounded-lg hover:bg-indigo-700 transition duration-300 font-medium flex items-center justify-center">
                <Play className="w-5 h-5 mr-2" />
                Start Scenario
              </button>
            </div>
          </div>
        ))}
      </div>

      {filteredScenarios.length === 0 && (
        <div className="text-center py-12">
          <div className="bg-gray-100 rounded-full w-16 h-16 flex items-center justify-center mx-auto mb-4">
            <Search className="w-8 h-8 text-gray-400" />
          </div>
          <h3 className="text-xl font-bold text-gray-900 mb-2">No scenarios found</h3>
          <p className="text-gray-600">Try adjusting your search or filter criteria</p>
        </div>
      )}
    </div>
  );
};

export default ScenarioBrowser;
